scwin.cvsslMgntNo;
scwin.CodeList;
scwin.loginDTO;
scwin.lobranCd;
scwin.lobranNm;
scwin.sDate;
scwin.nowDt;
scwin.vQryStDt;
scwin.vQryEndDt;
scwin.PcvsslMgntNo;

scwin.onpageload = function() {

    scwin.cvsslMgntNo = $c.data.getParameter("cvsslMgntNo") == null ? "" : $c.data.getParameter("cvsslMgntNo");  // 본선관리번호
	// scwin.CodeList = "^ ," + GauceUtil.getCodeList("OP120");
    // scwin.loginDTO = LoginUtil.getLoginDTO( request ); 
    scwin.lobranCd = $c.data.getMemInfo("lobranCd");
    scwin.lobranNm = $c.data.getMemInfo("lobranNm");
    scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.nowDt = $c.date.getServerDateTime("yyyyMMdd");
    scwin.nowDt2 = $c.date.getServerDateTime("yyyyMM");
    scwin.vQryStDt = scwin.nowDt.substring(0, 4) + "0101";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
    scwin.vQryEndDt = scwin.nowDt2 + $c.date.getLastDateOfMonth(scwin.nowDt2);  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
    scwin.PcvsslMgntNo = scwin.cvsslMgntNo;

    const codeOptions = [
        { grpCd : "SL001", compID : "gr_workIndictHistory:wrkPatternCd" } // 작업유형
        , { grpCd : "SL002", compID : "gr_workIndictHistory:wrkIndictPrgsStsCd" } // 작업상태
        , { grpCd : "OP120", compID : "" } // 
    ];
    $c.data.setCommonCode(codeOptions);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        $c.gus.cfDisableObjects([ica_wrkDt, ed_clntNo,ed_clntNm,ed_commCd,ed_commNm,ed_clntNo2,ed_clntNm2,ed_commCd2,ed_commNm2,ica_customsDt]);

        ica_arvStDt.setValue("20150101");
        ica_arvEndDt.setValue(scwin.vQryEndDt);

        ica_wrkDt.setValue(scwin.nowDt);

        // gr_stock.TitleHeight="30";
        // lc_stockYn.BindColVal = "1";
        acb_stockYn.setValue(1);

        $p.setTimeout(function() {
            // ica_arvStDt.setValue("20200101");
            // ica_arvEndDt.setValue("20200101");
            // acb_stockYn.setValue("");
        }, {"delay":50});

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 조회 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {  
	// 검색조건 필수 입력 체크
    var validate = await $c.gus.cfValidate([tbl_condition]);
  	if (!validate) {	 
  		return;
	}
    var validate1 = await await $c.date.diffDateMsg(ica_arvStDt.getValue(), ica_arvEndDt.getValue());
    if (!validate1) {	 
  		return;
	}
    var validate2 = await await $c.date.diffDateMsg(ica_wrkStDt.getValue(), ica_wrkEndDt.getValue());
    if (!validate2) {	 
  		return;
	}

  	var rs = await $c.sbm.execute(sbm_search);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){

        // ds_stock.sort("commNm", 0);
        var options = {};
        options.sortIndex = "commNm clntClsCd clntNm";
        options.sortOrder = "1 -1 1";
        ds_stock.multisort(options)

        var rowCnt = ds_stock.getRowCount();
        txt_totalRows.setValue(rowCnt);
        if(rowCnt > 0){
            ds_stock.setRowPosition(0);
        }

        await scwin.f_SetWrkIndict();

        if(ed_stockMgntNo.getValue() == ""){
            $c.gus.cfEnableObjects([ed_cvsslMgntNo2,ed_vsslNm2,ed_scalClntNo2,ed_scalCommCd2
            // ,img_PopUp4,img_PopUp5,img_PopUp6
            ,udc_cvsslMgntNo2
            ,udc_scalClntNo2
            ,udc_scalComm2
            ]);	
        } else {
            $c.gus.cfDisableObjects([ed_cvsslMgntNo2,ed_vsslNm2,ed_scalClntNo2,ed_scalCommCd2
            // ,img_PopUp4,img_PopUp5,img_PopUp6
            ,udc_cvsslMgntNo2
            ,udc_scalClntNo2
            ,udc_scalComm2
            ]);	
        }

        for (var i = 0 ; i < ds_stock.getRowCount() ; i++){
            if(ds_stock.getCellData(i, "stockWt") < 0){
                gr_stock.setCellBackgroundColor(i, "stockWt", "pink");
            }
            if(ds_stock.getCellData(i, "customsDt") != ""){
                gr_stock.setCellBackgroundColor(i, "outCnt", "#B5B2FF");
            }
        };
        var rs = await $c.sbm.execute(sbm_search2);
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            txt_totalRows2.setValue(ds_wrkIndictHistory.getRowCount());
        }
    };
};

//-------------------------------------------------------------------------
// 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_save = async function (index) {  	

    // if( !await $c.gus.cfValidate([ds_wrkIndict]) ) return;		
    // if( !await $c.gus.cfValidate([tbl_wrkIndict]) ) return;		

    if(ica_wrkDt.getValue() == ""){
        await $c.win.alert("작업지시 생성 시 작업일자는 필수입니다.");
        ica_wrkDt.focus();
        return false;		
    }		
    ds_wrkIndict.set("wrkDtShift", "D");
    ds_wrkIndict.set("wrkShift", "D");
    ds_wrkIndict.set("wrkIndictPrgsStsCd", "1");
    ds_wrkIndict.set("lobranCd", "6BB");
    ds_wrkIndict.set("wrkPlCd", "6E03");
    ds_wrkIndict.set("bulkScalCd", "H01");
    ds_wrkIndict.set("gaugePatternCd", "01");

    switch(index){
        case '1' :
            ds_wrkIndict.set("wrkPatternCd", "01");
            break;
        case '2' :
            ds_wrkIndict.set("wrkPatternCd", "02");
            if(ed_stockMgntNo.getValue() == ""){
                await $c.win.alert("출고 시 재고번호는 필수입니다.");
                ed_stockMgntNo.focus();
                return false;	  			
            }
            break;
        case '3' :
            ds_wrkIndict.set("wrkPatternCd", "03");
            break;
        case '4' :
            ds_wrkIndict.set("wrkPatternCd", "04");
            if(ed_stockMgntNo.getValue() == ""){
                await $c.win.alert("출고 시 재고번호는 필수입니다.");
                ed_stockMgntNo.focus();
                return false;	  			
            }
            break;
        case '5' :
            ds_wrkIndict.set("wrkPatternCd", "05");
            break;
        case '6' :
            ds_wrkIndict.set("wrkPatternCd", "06");
            if(ed_stockMgntNo.getValue() == ""){
                await $c.win.alert("출고 시 재고번호는 필수입니다.");
                ed_stockMgntNo.focus();
                return false;	  			
            }
            break;	

        case '7' :
            ds_wrkIndict.set("wrkPatternCd", "11");
            if(ed_stockMgntNo.getValue() == ""){
                await $c.win.alert("직출고 시 재고번호는 필수입니다.");
                ed_stockMgntNo.focus();
                return false;	  			
            }	
            break;	
        case '8' :
            ds_wrkIndict.set("wrkPatternCd", "09");
            if(ed_stockMgntNo.getValue() == ""){
                await $c.win.alert("단순계근 시 재고번호는 필수입니다.");
                ed_stockMgntNo.focus();
                return false;	  			
            }	
            break;	
        case '9' :
            ds_wrkIndict.set("wrkPatternCd", "10");
            if(ed_stockMgntNo.getValue() == ""){
                await $c.win.alert("개별출고 시 재고번호는 필수입니다.");
                ed_stockMgntNo.focus();
                return false;	  			
            }
            break;		
    }

    if(ed_cvsslMgntNo2.getValue() == "" && ed_clntNo2.getValue() == "" && ed_commCd2.getValue() == ""){		
        await $c.win.alert("작업지시 생성 시 본선/품목 혹은 화주/품목은 필수입니다. ");
        return false;		
    } else if(ed_cvsslMgntNo2.getValue() == "" && ed_commCd2.getValue() == "" && ed_clntNo2.getValue() != ""){
        await $c.win.alert("작업지시 생성 시 본선/품목 혹은 화주/품목은 필수입니다. ");
        return false;				
    } else if(ed_clntNo2.getValue() == "" && ed_commCd2.getValue() == "" && ed_cvsslMgntNo2.getValue() != ""){
        await $c.win.alert("작업지시 생성 시 본선/품목 혹은 화주/품목은 필수입니다. ");
        return false;	
    }else if(ed_clntNo2.getValue() != "" && ed_commCd2.getValue() == "" && ed_cvsslMgntNo2.getValue() != ""){
        await $c.win.alert("작업지시 생성 시 본선/품목 혹은 화주/품목은 필수입니다. ");
        return false;	
    }
    $c.sbm.execute(sbm_save);
};

//-------------------------------------------------------------------------
// 본선관리번호검색 팝업창 띄우기
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function() {
	var args = new Array();
	args[0] = ed_cvsslMgntNo.getValue(); //본선관리번호
	args[1] = ""; //수출입구분코드
    let win_url = "/ui/ds/sl/sl_101_01_01p.xml";
    let opts = {
        id : "sl_101_01_01p_Pop"
        , popupName : "본선관리번호검색팝업"
        , modal : true
        , type : "browserPopup"
        , width : 1100
        , height : 600
        , title : "본선관리번호검색팝업"
    };
    var rtnValues = await $c.win.openPopup(win_url, opts, args);
	if (rtnValues != null) {
		ed_cvsslMgntNo.setValue(rtnValues[0]); 
		ds_hidden.set("hd_vsslCd", rtnValues[1]); 
		ed_vsslNm.setValue(rtnValues[2]); 

	}	
};

