//-------------------------------------------------------------------------
// 작업지시 셋팅
//-------------------------------------------------------------------------  
scwin.f_SetWrkIndict = function() {
    if(ds_stock.getRowCount() == 0){
        scwin.f_Init();
    } else {
        var row = ds_stock.getRowPosition();
        ica_wrkDt.setValue(scwin.nowDt);
        ed_cvsslMgntNo2.setValue(ds_stock.getCellData(row, "cvsslMgntNo"));
        ed_vsslNm2.setValue(ds_stock.getCellData(row, "vsslNm"));
        ds_hidden.set("hd_vsslCd", ds_stock.getCellData(row, "vsslCd"));
        ed_scalClntNo2.setValue(ds_stock.getCellData(row, "scalClntNo"));
        ed_clntNo2.setValue(ds_stock.getCellData(row, "clntNo"));
        ed_clntNm2.setValue(ds_stock.getCellData(row, "clntNm"));
        ed_scalCommCd2.setValue(ds_stock.getCellData(row, "scalCommCd"));
        ed_commCd2.setValue(ds_stock.getCellData(row, "commCd"));
        ed_commNm2.setValue(ds_stock.getCellData(row, "commNm"));
        ed_stockMgntNo.setValue(ds_stock.getCellData(row, "stockMgntNo"));
        ica_customsDt.setValue(ds_stock.getCellData(row, "customsDt"));
        ed_inSeq.setValue(ds_stock.getCellData(row, "blBkNo"));
        $c.gus.cfDisableObjects([ed_cvsslMgntNo2,ed_vsslNm2,ed_scalClntNo2,ed_scalCommCd2
        // ,img_PopUp4,img_PopUp5,img_PopUp6
        ,udc_cvsslMgntNo2
        ,udc_scalClntNo2
        ,udc_scalComm2
        ]);	


    }
};

//-------------------------------------------------------------------------
// Pop up 
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  	// 선언부
	var rtnList;  // 공통POP-UP -> 요청화면 
	var pWhere;		// 조회조건
	switch (disGubun)
  	{
  		case 1:
			// 거래처 like 조건
  			var v_clntNo = "525083";
  			var v_itemCd = "SCAL_CLNT";	
