//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    var res = await $c.gus.cfCanOpenPopup(inObj, pairObj)
  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!res) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

scwin.ed_clntNm_onchange = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_clntNm, ed_scalClntNo, 1, false);
};

scwin.udc_scalClnt_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_scalClntNo.getValue(), ed_clntNm.getValue(), 'F', 'T');
};

scwin.ed_commNm_onchange = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_commNm, ed_scalCommCd, 3, false);
};

scwin.udc_scalComm_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(3, ed_scalCommCd.getValue(), ed_commNm.getValue(), 'F', 'T');
};

scwin.udc_cvsslMgnt_onclickEvent = function (e) {
    scwin.f_openPopUp();
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.clntClsCd_formatter = function(data){
    if (data == "2"){
        return "농협/축협";
    }else if(data == "1"){
        return "사협";
    }else {
        return "개별";
    }
};
scwin.udc_cvsslMgntNo2_onclickEvent = function (e) {
    scwin.f_openPopUp2();
};

scwin.btn_save_onclick = function (e) {
