scwin.udc_scalClnt_callBackFunc1 = async function(ref){
    var res = await $c.gus.cfIsNull(ref);
    if( !res && ref[0] != "N/A") {
        ed_scalClntNo.setValue(ref[0]);                  
        ed_clntNm.setValue(ref[1]); 
        ed_clntNo.setValue(ref[2]); 
    } else {
        ed_scalClntNo.setValue("");         
        ed_clntNm.setValue("");
        ed_clntNo.setValue("");
    }		
};

