scwin.excelDown = function(){
    const infoArr = [];
    const options = {
        fileName : "재고정보.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "재고정보",
        // startRowIndex: 2,
        type : "1",
        // removeColumns: "0,21",
        // hiddenVisible : true,
        oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
        evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
    };
    $c.data.downloadGridViewExcel(gr_stock, options, infoArr);


};
